import React, { useState, useContext } from 'react';
import { Link } from 'react-router-dom';
import { FaUser, FaThumbsUp, FaThumbsDown, FaComment, FaCalendarAlt } from 'react-icons/fa';
import { AuthContext } from '../context/AuthContext';
import { formatDate } from '../utils/formatDate';
import forumService from '../services/forumService';
import { toast } from 'react-toastify';

const ForumPostCard = ({ post, refreshPosts }) => {
  const { user } = useContext(AuthContext);
  const [isVoting, setIsVoting] = useState(false);

  const handleVote = async (type) => {
    if (!user) {
      toast.error('Please log in to vote on posts');
      return;
    }

    try {
      setIsVoting(true);
      await forumService.voteOnPost(post._id, type);
      refreshPosts(); // Refresh posts to get updated vote count
    } catch (error) {
      toast.error(error.response?.data?.message || 'Error voting on post');
    } finally {
      setIsVoting(false);
    }
  };

  const truncateContent = (content, maxLength = 150) => {
    if (!content) return '';
    if (content.length <= maxLength) return content;
    return content.substring(0, maxLength) + '...';
  };

  // Check if user has already voted
  const hasUpvoted = user && post.upvotes.includes(user._id);
  const hasDownvoted = user && post.downvotes.includes(user._id);

  return (
    <div className="bg-white rounded-lg shadow-md p-4 mb-4 hover:shadow-lg transition-shadow">
      <div className="flex justify-between items-start mb-3">
        <h3 className="text-xl font-semibold text-gray-800">
          <Link to={`/forum/post/${post._id}`} className="hover:text-green-600 transition-colors">
            {post.title}
          </Link>
        </h3>
        <div className="bg-green-100 text-green-800 text-xs font-medium px-2.5 py-0.5 rounded">
          {post.category}
        </div>
      </div>

      <p className="text-gray-600 mb-4">{truncateContent(post.content)}</p>

      <div className="flex items-center text-gray-500 text-sm mb-3">
        <div className="flex items-center mr-4">
          <FaUser className="mr-1" />
          <span>{post.author.name}</span>
        </div>
        <div className="flex items-center">
          <FaCalendarAlt className="mr-1" />
          <span>{formatDate(post.createdAt, { withRelativeTime: true })}</span>
        </div>
      </div>

      <div className="flex items-center justify-between border-t pt-3">
        <div className="flex items-center space-x-4">
          <button
            disabled={isVoting}
            onClick={() => handleVote('upvote')}
            className={`flex items-center space-x-1 ${
              hasUpvoted ? 'text-green-600' : 'text-gray-500'
            } hover:text-green-600 disabled:opacity-50`}
          >
            <FaThumbsUp />
            <span>{post.upvotes.length}</span>
          </button>
          <button
            disabled={isVoting}
            onClick={() => handleVote('downvote')}
            className={`flex items-center space-x-1 ${
              hasDownvoted ? 'text-red-600' : 'text-gray-500'
            } hover:text-red-600 disabled:opacity-50`}
          >
            <FaThumbsDown />
            <span>{post.downvotes.length}</span>
          </button>
        </div>

        <Link
          to={`/forum/post/${post._id}`}
          className="flex items-center text-gray-500 hover:text-green-600"
        >
          <FaComment className="mr-1" />
          <span>{post.comments ? post.comments.length : 0} Comments</span>
        </Link>
      </div>
    </div>
  );
};

export default ForumPostCard;
